%%%%%%%%%% Function fRat55ValV01.m %%%%%%%%%%% Function Culclate rat55 value, ver.1%% Kei Nakamura% Created on Friday, September 28th 2007.% Modified on%% function vl = fRat55ValV01(x,cff);% gives value for rational 55% vl: value% x: x% cff: rat55 coefficients (11)function vl = fRat55ValV01(x,cff);nmr = cff(1)*x.^5+cff(2)*x.^4+cff(3)*x.^3+cff(4)*x.^2+cff(5)*x+cff(6);  % numeratordnm = x.^5+cff(7)*x.^4+cff(8)*x.^3+cff(9)*x.^2+cff(10)*x+cff(11);       % denominatorvl = nmr./dnm;
